"use strict";(globalThis.webpackChunk_servicenow_sdk_docs=globalThis.webpackChunk_servicenow_sdk_docs||[]).push([[57261],{75852(e){e.exports=JSON.parse('{"tag":{"label":"tools","permalink":"/sdk/tags/tools","allTagsPath":"/sdk/tags","count":2,"items":[{"id":"guides/building-ai-agents-guide","title":"Building AI Agents Guide","description":"Build and configure ServiceNow AI Agents and AI Agentic Workflows using the Fluent SDK. AI Agents perform tasks with tools (CRUD, script, OOB, reference-based), while AI Agentic Workflows orchestrate multiple agents as a team. This guide covers end-to-end creation: authentication, tool configuration, instructions authoring, triggers, ACL deployment, and editing existing agents. Requires SDK 4.4.0 or higher.","permalink":"/sdk/guides/building-ai-agents-guide"},{"id":"guides/nowassist-skills-guide","title":"Now Assist Skills Guide","description":"Create and configure Now Assist Skills using the NowAssistSkillConfig API in the Fluent SDK. Skills use configured prompts to generate AI responses from an LLM, optionally enriched by inputs and tools (script, inline script, web search, subflows, flow actions, decision branches). This guide covers the full lifecycle: provider/model selection, input configuration, tool wiring, prompt authoring, security controls, and deployment. Requires SDK 4.6.0 or higher.","permalink":"/sdk/guides/nowassist-skills-guide"}],"unlisted":false}}')}}]);